#include <stdio.h>
#include <signal.h>

/* Test mode: sigset operations are tested directly */

int main(void) {
    {
        sigset_t s;
        sigemptyset(&s);
        printf("%d\n", (int)(sigismember(&s, SIGINT)));
        printf("%d\n", (int)(sigismember(&s, SIGTERM)));
    }
    {
        sigset_t s;
        sigemptyset(&s);
        sigaddset(&s, SIGINT);
        printf("%d\n", (int)(sigismember(&s, SIGINT)));
        printf("%d\n", (int)(sigismember(&s, SIGTERM)));
    }
    {
        sigset_t s;
        sigemptyset(&s);
        sigaddset(&s, SIGINT);
        sigaddset(&s, SIGTERM);
        sigaddset(&s, SIGCHLD);
        printf("%d\n", (int)(sigismember(&s, SIGINT)));
        printf("%d\n", (int)(sigismember(&s, SIGTERM)));
        printf("%d\n", (int)(sigismember(&s, SIGCHLD)));
        printf("%d\n", (int)(sigismember(&s, SIGKILL)));
    }
    {
        sigset_t s;
        sigemptyset(&s);
        sigaddset(&s, SIGINT);
        sigaddset(&s, SIGTERM);
        sigdelset(&s, SIGTERM);
        printf("%d\n", (int)(sigismember(&s, SIGINT)));
        printf("%d\n", (int)(sigismember(&s, SIGTERM)));
    }
    {
        sigset_t s;
        sigemptyset(&s);
        printf("%d\n", (int)(sigismember(&s, SIGUSR1)));
        printf("%d\n", (int)(sigismember(&s, SIGKILL)));
    }
    return 0;
}

